    def sqrt(self, num):
        if num < 0:
            raise ValueError("Input must be a non-negative number")
        return math.sqrt(num)

    def power(self, num, exponent):
        return num ** exponent

    def root(self, num, degree):
        if num < 0 and degree % 2 == 0:
            raise ValueError("Input must be a non-negative number for even degree roots")
