            return Figure(math.factorial(int(self.x)))
        else:
            raise ValueError("Factorial is not defined for negative or non-integer numbers")

    def sin(self):
        return Figure(math.sin(self.x))

    def cos(self):
        return Figure(math.cos(self.x))

    def tan(self):
        return Figure(math.tan(self.x))

    def exp(self):
        return Figure(math.exp(self.x))

    def sqrt(self):
        if self.x >= 0:
            return Figure(math.sqrt(self.x))
        else:
            raise ValueError("Square root is not defined for negative numbers")

